package entity

import (
	"math"
	"testing"

	"github.com/stretchr/testify/require"
)

// TestUnitOrderCalculateTotalEdgeCases adds a few edge‑case scenarios that are
// not covered by the existing suite (e.g. TestUnitOrderCalculateTotal* and the
// extended tests).  The goal is to verify that `CalculateTotal` is a pure
// arithmetic aggregation – it does **not** perform any validation or special
// handling of extreme values.  Each sub‑test is isolated and does not rely on
// any shared state.
//
// The test cases are:
//
//   1. NegativeQuantity – an item with a negative quantity (invalid from a
//      business‑logic point of view) should still be summed, i.e. the total
//      becomes negative for that line.
//   2. NegativePrice – same idea, but the price is negative.
//   3. HugeValues – price and quantity are chosen so that the multiplication
//      overflows the float64 range.  The result should be +Inf (the IEEE‑754
//      behaviour of Go’s float arithmetic).
//   4. VerySmallPriceLargeQuantity – a tiny price multiplied by a huge quantity
//      tests the precision of the accumulation.
//   5. MixedZeroAndPositive – a mixture of zero‑price/zero‑quantity items with
//      normal items; the zero contributions must not affect the sum.
func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	t.Parallel()

	type tc struct {
		name     string
		items    []OrderItem
		expected float64
		// if expectedIsInf is true we only check that the result is +Inf.
		expectedIsInf bool
	}

	cases := []tc{
		{
			name: "NegativeQuantity",
			items: []OrderItem{
				{ProductID: 1, Quantity: -3, Price: 100},
				{ProductID: 2, Quantity: 2, Price: 50},
			},
			// (-3)*100 + 2*50 = -300 + 100 = -200
			expected: -200,
		},
		{
			name: "NegativePrice",
			items: []OrderItem{
				{ProductID: 1, Quantity: 4, Price: -25},
				{ProductID: 2, Quantity: 1, Price: 100},
			},
			// 4*(-25) + 1*100 = -100 + 100 = 0
			expected: 0,
		},
		{
			name: "HugeValues",
			items: []OrderItem{
				{ProductID: 1, Quantity: 2, Price: math.MaxFloat64 / 2},
			},
			// (MaxFloat64/2) * 2 = MaxFloat64, which is still finite.
			// Adding one more such line forces overflow to +Inf.
			expectedIsInf: true,
			expected:      math.Inf(1), // placeholder – the check uses IsInf
		},
		{
			name: "VerySmallPriceLargeQuantity",
			items: []OrderItem{
				{ProductID: 1, Quantity: 10_000_000, Price: 0.0000001},
			},
			// 10_000_000 * 0.0000001 = 1.0
			expected: 1.0,
		},
		{
			name: "MixedZeroAndPositive",
			items: []OrderItem{
				{ProductID: 1, Quantity: 5, Price: 0},      // zero price
				{ProductID: 2, Quantity: 0, Price: 123.45}, // zero quantity
				{ProductID: 3, Quantity: 3, Price: 20.5},
			},
			// 5*0 + 0*123.45 + 3*20.5 = 61.5
			expected: 61.5,
		},
	}

	for _, c := range cases {
		c := c // capture range variable
		t.Run(c.name, func(t *testing.T) {
			t.Parallel()

			o := Order{
				Items: c.items,
			}
			o.CalculateTotal()

			if c.expectedIsInf {
				require.True(t, math.IsInf(o.Total, +1), "total should be +Inf")
				return
			}
			require.Equal(t, c.expected, o.Total)
		})
	}
}
```

