package api_test

import (
	"net/http"
	"net/http/httptest"
	"testing"

	"github.com/go-chi/chi/v5"
	"github.com/stretchr/testify/require"

	// import the project’s top‑level package – adjust the module name if it differs
	"beanbrew/internal/api"
	"beanbrew/internal/handler"
	"beanbrew/internal/repository"
	"beanbrew/internal/usecase"
	"beanbrew/internal/testhelper"
)

// TestAPIOrderFullFlow tests the *happy‑path* of the whole system:
//
//   1. Create a category (POST /categories)
//   2. Create a product that belongs to that category (POST /products)
//   3. Create an order that contains the product (POST /orders)
//   4. Process the order (POST /orders/{id}/process)
//   5. Complete the order (POST /orders/{id}/complete)
//
// The test uses the same infrastructure that the other API tests use:
//   * a fresh in‑memory SQLite DB (`setupTestDB`)
//   * the full chi router with all four handlers attached (`setupTestServer`)
//   * helper functions from `testhelper` for posting JSON and decoding responses.
//
// All steps are verified by checking the HTTP status code **and** by fetching the
// order after each state change to assert the expected `status` field.
func TestAPIOrderFullFlow(t *testing.T) {
	// ----------------------------------------------------------------------
	// 1️⃣  Test‑setup – fresh DB + full HTTP server
	// ----------------------------------------------------------------------
	db := testhelper.SetupTestDB(t) // creates :memory: SQLite and runs migrations
	// Build the repository‑usecase‑handler stack exactly as the production code does.
	catRepo := repository.NewCategorySQLite(db)
	prodRepo := repository.NewProductSQLite(db)
	orderRepo := repository.NewOrderSQLite(db)

	catUC := usecase.NewCategoryUseCase(catRepo)
	prodUC := usecase.NewProductUseCase(prodRepo, catRepo)
	orderUC := usecase.NewOrderUseCase(orderRepo, prodRepo)

	catH := handler.NewCategoryHandler(catUC)
	prodH := handler.NewProductHandler(prodUC)
	orderH := handler.NewOrderHandler(orderUC)

	r := chi.NewRouter()
	r.Post("/categories", catH.Create)
	r.Post("/products", prodH.Create)
	r.Post("/orders", orderH.Create)
	r.Post("/orders/{id}/process", orderH.Process)
	r.Post("/orders/{id}/complete", orderH.Complete)
	r.Get("/orders/{id}", orderH.GetByID)

	ts := httptest.NewServer(r)
	t.Cleanup(ts.Close)

	// ----------------------------------------------------------------------
	// 2️⃣  Create a category
	// ----------------------------------------------------------------------
	categoryPayload := map[string]any{
		"name":        "Кофе",
		"slug":        "coffee",
		"description": "Все виды кофе",
		"sort_order":  1,
	}
	resp := testhelper.PostJSON(t, ts.URL+"/categories", categoryPayload)
	require.Equal(t, http.StatusCreated, resp.StatusCode)

	var catResp struct {
		ID int64 `json:"id"`
	}
	testhelper.DecodeBody(t, resp, &catResp)
	require.Greater(t, catResp.ID, int64(0), "category ID must be > 0")

	// ----------------------------------------------------------------------
	// 3️⃣  Create a product that belongs to the category we just created
	// ----------------------------------------------------------------------
	productPayload := map[string]any{
		"name":        "Латте",
		"category_id": catResp.ID,
		"price":       350.0,
		"description": "Молочный кофе",
		"image_url":   "https://example.com/latte.png",
		"in_stock":    true,
	}
	resp = testhelper.PostJSON(t, ts.URL+"/products", productPayload)
	require.Equal(t, http.StatusCreated, resp.StatusCode)

	var prodResp struct {
		ID int64 `json:"id"`
	}
	testhelper.DecodeBody(t, resp, &prodResp)
	require.Greater(t, prodResp.ID, int64(0), "product ID must be > 0")

	// ----------------------------------------------------------------------
	// 4️⃣  Create an order that contains the product
	// ----------------------------------------------------------------------
	orderPayload := map[string]any{
		"customer_id": "alice@example.com",
		"items": []any{
			map[string]any{
				"product_id": prodResp.ID,
				"quantity":   2,
			},
		},
	}
	resp = testhelper.PostJSON(t, ts.URL+"/orders", orderPayload)
	require.Equal(t, http.StatusCreated, resp.StatusCode)

	var orderResp struct {
		ID int64 `json:"id"`
	}
	testhelper.DecodeBody(t, resp, &orderResp)
	require.Greater(t, orderResp.ID, int64(0), "order ID must be > 0")

	// ----------------------------------------------------------------------
	// 5️⃣  Verify the freshly created order is in **new** status
	// ----------------------------------------------------------------------
	resp = testhelper.Get(t, ts.URL+"/orders/"+testhelper.Itoa(orderResp.ID))
	require.Equal(t, http.StatusOK, resp.StatusCode)

	var orderGet struct {
		Status string `json:"status"`
	}
	testhelper.DecodeBody(t, resp, &orderGet)
	require.Equal(t, "new", orderGet.Status, "order should start in 'new' status")

	// ----------------------------------------------------------------------
	// 6️⃣  Process the order (new → processing)
	// ----------------------------------------------------------------------
	resp = testhelper.Post(t, ts.URL+"/orders/"+testhelper.Itoa(orderResp.ID)+"/process")
	require.Equal(t, http.StatusOK, resp.StatusCode)

	// Fetch again and assert the new status
	resp = testhelper.Get(t, ts.URL+"/orders/"+testhelper.Itoa(orderResp.ID))
	require.Equal(t, http.StatusOK, resp.StatusCode)
	testhelper.DecodeBody(t, resp, &orderGet)
	require.Equal(t, "processing", orderGet.Status, "order should be 'processing' after Process")

	// ----------------------------------------------------------------------
	// 7️⃣  Complete the order (processing → completed)
	// ----------------------------------------------------------------------
	resp = testhelper.Post(t, ts.URL+"/orders/"+testhelper.Itoa(orderResp.ID)+"/complete")
	require.Equal(t, http.StatusOK, resp.StatusCode)

	// Final verification – the order must be in **completed** state
	resp = testhelper.Get(t, ts.URL+"/orders/"+testhelper.Itoa(orderResp.ID))
	require.Equal(t, http.StatusOK, resp.StatusCode)
	testhelper.DecodeBody(t, resp, &orderGet)
	require.Equal(t, "completed", orderGet.Status, "order should be 'completed' after Complete")
}
```

