package entity

import (
	"math"
	"testing"
)

// TestUnitOrderCalculateTotalEdgeCases – новые edge‑case‑тесты для
// метода Order.CalculateTotal().  Они не пересекаются с уже существующими
// TestUnitOrderCalculateTotal*, TestUnitOrderCalculateTotalVariousItemCounts
// и другими тестами из `entity_order_extended`.
func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	// вспомогательная функция – создаёт Order с переданными items
	newOrder := func(items []OrderItem) *Order {
		o := &Order{
			Items: items,
		}
		o.CalculateTotal()
		return o
	}

	t.Run("LargeValuesOverflow", func(t *testing.T) {
		// math.MaxFloat64/2 * 3 → +Inf (переполнение float64)
		huge := math.MaxFloat64 / 2
		o := newOrder([]OrderItem{
			{ProductID: 1, Quantity: 3, Price: huge},
		})
		if !math.IsInf(o.Total, +1) {
			t.Fatalf("expected Total to be +Inf, got %v", o.Total)
		}
	})

	t.Run("ZeroPrice", func(t *testing.T) {
		o := newOrder([]OrderItem{
			{ProductID: 2, Quantity: 5, Price: 0},
			{ProductID: 3, Quantity: 10, Price: 0},
		})
		if o.Total != 0 {
			t.Fatalf("expected Total 0, got %v", o.Total)
		}
	})

	t.Run("NegativePrice", func(t *testing.T) {
		// Валидация цены происходит в UseCase, а не в сущности,
		// поэтому CalculateTotal должна просто суммировать любые значения.
		o := newOrder([]OrderItem{
			{ProductID: 4, Quantity: 2, Price: -10.0},
			{ProductID: 5, Quantity: 1, Price: 5.0},
		})
		expected := -15.0
		if o.Total != expected {
			t.Fatalf("expected Total %v, got %v", expected, o.Total)
		}
	})

	t.Run("ZeroQuantity", func(t *testing.T) {
		o := newOrder([]OrderItem{
			{ProductID: 6, Quantity: 0, Price: 100.0},
			{ProductID: 7, Quantity: 3, Price: 20.0},
		})
		// первый элемент не вносит вклад, второй – 60
		expected := 60.0
		if o.Total != expected {
			t.Fatalf("expected Total %v, got %v", expected, o.Total)
		}
	})

	t.Run("DuplicateProductIDs", func(t *testing.T) {
		o := newOrder([]OrderItem{
			{ProductID: 8, Quantity: 1, Price: 30.0},
			{ProductID: 8, Quantity: 2, Price: 30.0},
			{ProductID: 9, Quantity: 1, Price: 50.0},
		})
		// 1*30 + 2*30 + 1*50 = 140
		expected := 140.0
		if o.Total != expected {
			t.Fatalf("expected Total %v, got %v", expected, o.Total)
		}
	})

	t.Run("InfinityAndNaN", func(t *testing.T) {
		o := newOrder([]OrderItem{
			{ProductID: 10, Quantity: 1, Price: math.Inf(1)},
			{ProductID: 11, Quantity: 1, Price: math.Inf(-1)},
		})
		if !math.IsNaN(o.Total) {
			t.Fatalf("expected Total to be NaN, got %v", o.Total)
		}
	})

	t.Run("HighPrecision", func(t *testing.T) {
		// 0.123456789 * 1 000 000 = 123456.789
		price := 0.123456789
		qty := 1_000_000
		o := newOrder([]OrderItem{
			{ProductID: 12, Quantity: qty, Price: price},
		})
		expected := 123456.789
		const eps = 1e-9 // достаточно точный порог для данного расчёта
		if math.Abs(o.Total-expected) > eps {
			t.Fatalf("expected Total ≈ %v (±%v), got %v", expected, eps, o.Total)
		}
	})
}
