// api/order_test.go
package api

import (
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strconv"
	"testing"

	"github.com/go-chi/chi/v5"
	"github.com/stretchr/testify/require"
)

// ---------------------------------------------------------------------------
// Helper structs that mirror the JSON payloads used by the API
// ---------------------------------------------------------------------------

type categoryReq struct {
	Name string `json:"name"`
	Slug string `json:"slug"`
}

type productReq struct {
	Name       string  `json:"name"`
	CategoryID int64   `json:"category_id"`
	Price      float64 `json:"price"`
}

type orderReq struct {
	CustomerID string          `json:"customer_id"`
	Items      []orderItemReq `json:"items"`
}

type orderItemReq struct {
	ProductID int64 `json:"product_id"`
	Quantity  int   `json:"quantity"`
}

// ---------------------------------------------------------------------------
// Test: full happy‑path flow
//   1. Create a category
//   2. Create a product that belongs to the category
//   3. Create an order that contains the product
//   4. Process the order (new → processing)
//   5. Complete the order (processing → completed)
//   6. Verify the final state and the total amount
// ---------------------------------------------------------------------------

func TestAPIOrderFullFlowCreateCategoryProductOrderProcessComplete(t *testing.T) {
	// -----------------------------------------------------------------------
	// 1️⃣  Set up a fresh in‑memory server (all layers are wired together)
	// -----------------------------------------------------------------------
	srv := setupTestServer(t) // defined in testhelper_test.go
	client := srv.Client()
	baseURL := srv.URL

	// -----------------------------------------------------------------------
	// 2️⃣  Create a category – we need its ID for the product
	// -----------------------------------------------------------------------
	catPayload := categoryReq{
		Name: "Кофе",
		Slug: "coffee",
	}
	catResp := postJSON(t, client, baseURL+"/categories", catPayload)
	require.Equal(t, http.StatusCreated, catResp.Code)

	var catCreated struct {
		ID int64 `json:"id"`
	}
	decodeBody(t, catResp.Body, &catCreated)

	// -----------------------------------------------------------------------
	// 3️⃣  Create a product that belongs to the newly created category
	// -----------------------------------------------------------------------
	prodPayload := productReq{
		Name:       "Латте",
		CategoryID: catCreated.ID,
		Price:      350.0,
	}
	prodResp := postJSON(t, client, baseURL+"/products", prodPayload)
	require.Equal(t, http.StatusCreated, prodResp.Code)

	var prodCreated struct {
		ID int64 `json:"id"`
	}
	decodeBody(t, prodResp.Body, &prodCreated)

	// -----------------------------------------------------------------------
	// 4️⃣  Create an order that contains the product (quantity = 2)
	// -----------------------------------------------------------------------
	orderPayload := orderReq{
		CustomerID: "alice@example.com",
		Items: []orderItemReq{
			{
				ProductID: prodCreated.ID,
				Quantity:  2,
			},
		},
	}
	orderResp := postJSON(t, client, baseURL+"/orders", orderPayload)
	require.Equal(t, http.StatusCreated, orderResp.Code)

	var orderCreated struct {
		ID int64 `json:"id"`
	}
	decodeBody(t, orderResp.Body, &orderCreated)

	// -----------------------------------------------------------------------
	// 5️⃣  Verify that the order was created with status **new** and the
	//     correct total (2 × 350 = 700)
	// -----------------------------------------------------------------------
	getResp := doRequest(t, client, http.MethodGet,
		baseURL+"/orders/"+strconv.FormatInt(orderCreated.ID, 10), nil)
	require.Equal(t, http.StatusOK, getResp.Code)

	var orderGet struct {
		ID         int64   `json:"id"`
		CustomerID string  `json:"customer_id"`
		Status     string  `json:"status"`
		Total      float64 `json:"total"`
		Items      []struct {
			ProductID int64   `json:"product_id"`
			Quantity  int     `json:"quantity"`
			Price     float64 `json:"price"`
		} `json:"items"`
	}
	decodeBody(t, getResp.Body, &orderGet)

	require.Equal(t, "new", orderGet.Status)
	require.InDelta(t, 700.0, orderGet.Total, 0.01)
	require.Len(t, orderGet.Items, 1)
	require.Equal(t, prodCreated.ID, orderGet.Items[0].ProductID)
	require.Equal(t, 2, orderGet.Items[0].Quantity)
	require.InDelta(t, 350.0, orderGet.Items[0].Price, 0.01)

	// -----------------------------------------------------------------------
	// 6️⃣  Process the order (new → processing)
	// -----------------------------------------------------------------------
	processResp := doRequest(t, client, http.MethodPost,
		baseURL+"/orders/"+strconv.FormatInt(orderCreated.ID, 10)+"/process", nil)
	require.Equal(t, http.StatusOK, processResp.Code)

	// Verify the status changed to **processing**
	getResp = doRequest(t, client, http.MethodGet,
		baseURL+"/orders/"+strconv.FormatInt(orderCreated.ID, 10), nil)
	require.Equal(t, http.StatusOK, getResp.Code)
	decodeBody(t, getResp.Body, &orderGet)
	require.Equal(t, "processing", orderGet.Status)

	// -----------------------------------------------------------------------
	// 7️⃣  Complete the order (processing → completed)
	// -----------------------------------------------------------------------
	completeResp := doRequest(t, client, http.MethodPost,
		baseURL+"/orders/"+strconv.FormatInt(orderCreated.ID, 10)+"/complete", nil)
	require.Equal(t, http.StatusOK, completeResp.Code)

	// Final verification – status must be **completed**
	getResp = doRequest(t, client, http.MethodGet,
		baseURL+"/orders/"+strconv.FormatInt(orderCreated.ID, 10), nil)
	require.Equal(t, http.StatusOK, getResp.Code)
	decodeBody(t, getResp.Body, &orderGet)
	require.Equal(t, "completed", orderGet.Status)
	require.InDelta(t, 700.0, orderGet.Total, 0.01) // total must stay unchanged
}

// ---------------------------------------------------------------------------
// Helper functions (thin wrappers around the helpers that already exist in
// testhelper_test.go). They are kept local to this file so the test can be
// copy‑pasted into a fresh repository without pulling in unrelated helpers.
// ---------------------------------------------------------------------------

func postJSON(t *testing.T, client *http.Client, url string, payload any) *httptest.ResponseRecorder {
	body, err := json.Marshal(payload)
	require.NoError(t, err)

	req, err := http.NewRequest(http.MethodPost, url, bytes.NewReader(body))
	require.NoError(t, err)
	req.Header.Set("Content-Type", "application/json")

	rr := httptest.NewRecorder()
	chi.NewRouter().ServeHTTP(rr, req) // dummy router – the real request is sent via client
	resp, err := client.Do(req)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Convert the *http.Response into a *httptest.ResponseRecorder so the
	// existing decodeBody helper can be reused.
	rec := httptest.NewRecorder()
	rec.Code = resp.StatusCode
	rec.Body = new(bytes.Buffer)
	_, _ = rec.Body.ReadFrom(resp.Body)
	return rec
}

// doRequest is a tiny wrapper for GET/POST/PUT/DELETE that returns a
// *httptest.ResponseRecorder (the same shape used by the other API tests).
func doRequest(t *testing.T, client *http.Client, method, url string, body []byte) *httptest.ResponseRecorder {
	req, err := http.NewRequest(method, url, bytes.NewReader(body))
	require.NoError(t, err)
	if body != nil {
		req.Header.Set("Content-Type", "application/json")
	}
	resp, err := client.Do(req)
	require.NoError(t, err)
	defer resp.Body.Close()

	rec := httptest.NewRecorder()
	rec.Code = resp.StatusCode
	rec.Body = new(bytes.Buffer)
	_, _ = rec.Body.ReadFrom(resp.Body)
	return rec
}
