// TestUnitOrderCalculateTotalEdgeCases – новые edge‑case‑тесты для метода
// Order.CalculateTotal().  Они дополняют уже существующие наборы
// (TestUnitOrderCalculateTotal*, TestUnitOrderCalculateTotalVariousItemCounts и т.п.)
// и проверяют поведения, которые пока не покрыты:
//
//   1. Переполнение float64 (MaxFloat64 * 2 → +Inf).
//   2. Сумма, получающаяся из MaxFloat64 (не‑переполняется).
//   3. Товар с нулевой ценой, но огромным количеством (проверка, что 0*qty = 0).
//   4. Отрицательное количество (корректно суммируется, хотя валидация должна отсеять).
//   5. Отрицательная цена (аналогично пункту 4).
//   6. Дублирование ProductID с разными ценами – каждая позиция считается отдельно.
//   7. Позиции с разными знаками (положительные и отрицательные) – итог может быть 0.
//
// Тест построен как table‑driven, каждый кейс – отдельный sub‑test через t.Run().
// Это соответствует стилю остальных тестов проекта.

func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	type testCase struct {
		name        string
		items       []OrderItem
		wantTotal   float64
		wantIsInf   bool // true → ожидаем +Inf
		wantIsNaN   bool // true → ожидаем NaN (не используется сейчас, но оставляем для расширения)
		descr       string
	}

	maxF := math.MaxFloat64

	cases := []testCase{
		{
			name: "max_float_single_item",
			items: []OrderItem{
				{ProductID: 1, Quantity: 1, Price: maxF},
			},
			wantTotal: maxF,
			descr:     "один элемент с максимальной ценой – не должно переполняться",
		},
		{
			name: "max_float_overflow",
			items: []OrderItem{
				{ProductID: 1, Quantity: 1, Price: maxF},
				{ProductID: 2, Quantity: 1, Price: maxF},
			},
			wantIsInf: true,
			descr:    "два элемента с MaxFloat64 → сумма = +Inf",
		},
		{
			name: "zero_price_huge_quantity",
			items: []OrderItem{
				{ProductID: 1, Quantity: 1_000_000, Price: 0},
			},
			wantTotal: 0,
			descr:    "цена 0, но количество огромное – итог 0",
		},
		{
			name: "negative_quantity",
			items: []OrderItem{
				{ProductID: 1, Quantity: -5, Price: 100},
			},
			wantTotal: -500,
			descr:    "отрицательное количество (невалидно, но метод просто суммирует)",
		},
		{
			name: "negative_price",
			items: []OrderItem{
				{ProductID: 1, Quantity: 3, Price: -20},
			},
			wantTotal: -60,
			descr:    "отрицательная цена (невалидно, но метод просто суммирует)",
		},
		{
			name: "duplicate_product_ids_different_prices",
			items: []OrderItem{
				{ProductID: 42, Quantity: 2, Price: 150},
				{ProductID: 42, Quantity: 1, Price: 200},
			},
			wantTotal: 500, // 2*150 + 1*200
			descr:    "один и тот же ProductID, но разные цены – обе позиции учитываются",
		},
		{
			name: "mixed_signs",
			items: []OrderItem{
				{ProductID: 1, Quantity: 3, Price: 100},   // +300
				{ProductID: 2, Quantity: 2, Price: -150}, // -300
			},
			wantTotal: 0,
			descr:    "положительные и отрицательные позиции, итог 0",
		},
	}

	for _, tc := range cases {
		tc := tc // capture range variable
		t.Run(tc.name, func(t *testing.T) {
			o := &Order{
				Items: tc.items,
			}
			o.CalculateTotal()

			if tc.wantIsInf {
				if !math.IsInf(o.Total, +1) {
					t.Fatalf("%s: ожидаем +Inf, получили %v", tc.descr, o.Total)
				}
				return
			}
			if tc.wantIsNaN {
				if !math.IsNaN(o.Total) {
					t.Fatalf("%s: ожидаем NaN, получили %v", tc.descr, o.Total)
				}
				return
			}
			if o.Total != tc.wantTotal {
				t.Fatalf("%s: ожидаем %v, получили %v", tc.descr, tc.wantTotal, o.Total)
			}
		})
	}
}
